def count_primes(n: int) -> int:
    if n <= 2:
        return 0
    is_prime = [True] * n
    is_prime[0] = is_prime[1] = False
    p = 2
    while p * p < n:
        if is_prime[p]:
            step = p
            start = p * p
            for j in range(start, n, step):
                is_prime[j] = False
        p += 1
    return sum(is_prime)

